    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseA(pNonce * 0x93B5088D067477C3ULL + 0xFBBF4BA2675C5EF9ULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseC(pNonce * 0xF3D8994FB25B0849ULL + 0xC55667015C8DADD6ULL);
