    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0xA2EB0A75414A533BULL + 0x9525CDE5D3B212C4ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseA(pNonce * 0x8F4B4D383C4D8789ULL + 0xEB26F517C1FAF46BULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseA(pNonce * 0xF388B3525528EF73ULL + 0xB0DDAD43EE0D5D56ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseB(pNonce * 0x94C1A0320AB7CF87ULL + 0xB1660CF14D757FB0ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0xB81C375F25519881ULL + 0x9F61633007E344FEULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseB(pNonce * 0x858EB15FAF594A07ULL + 0xD895D2D7507C1944ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseA(pNonce * 0xDD6E5EE2E7F3BE75ULL + 0xF277C57F712D2BA0ULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0x953BCB88D37FC643ULL + 0xEEAB1B3B9901A10FULL);
