            //
            aOrbiterB = (aOrbiterB + aOrbiterF) + 8999390164504650791U;
            aOrbiterG = ((aOrbiterG ^ aOrbiterB) ^ 5127310059943116957U) ^ aNonceWordM;
            aOrbiterG = RotL64((aOrbiterG * 259510148510727113U), 47U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterD) + 8160746402587044135U;
            aOrbiterB = (((aOrbiterB ^ aOrbiterA) ^ 17653224260811646134U) ^ aOrbiterUpdateSaltF[(((31U - aIndex) + 16U)) & S_SALT1]) ^ aNonceWordN;
            aOrbiterB = RotL64((aOrbiterB * 16405593484403522897U), 27U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterB) + 3705506125277860984U) + aOrbiterUpdateSaltE[((aIndex + 9U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterI) ^ 17695637239713469929U;
            aOrbiterE = RotL64((aOrbiterE * 4732856504641981635U), 13U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterC) + 2443615883815630341U;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterF) ^ 8631370031774678245U) ^ aNonceWordD;
            aOrbiterJ = RotL64((aOrbiterJ * 452722496338007861U), 29U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterG) + 9462612322672951680U;
