            aOrbiterF = RotL64((aOrbiterF * 13154106922042097229U), 3U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterI) + 268988471208320453U;
            aOrbiterC = (aOrbiterC ^ aOrbiterH) ^ 6572891086005984213U;
            aOrbiterC = RotL64((aOrbiterC * 16494801366535041425U), 39U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterK) + 16114400936380742757U;
