            //
            aIngress = RotL64(aOrbiterB, 43U) ^ aOrbiterH;
            aIngress = aIngress + (aOrbiterC ^ RotL64(aOrbiterA, 5U));
            aIngress = aIngress + (RotL64(aOrbiterE, 34U) ^ aOrbiterI);
            aIngress = aIngress + (aOrbiterD ^ RotL64(aOrbiterJ, 27U));
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterK, 53U));
