            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererC = aWandererC + (((RotL64(aCross, 51U) + aOrbiterI) + RotL64(aOrbiterB, 23U)) + aNonceWordO);
            aWandererG = aWandererG ^ (((RotL64(aIngress, 23U) + RotL64(aOrbiterH, 54U)) + aOrbiterJ) + aWandererUpdateSaltF[(((31U - aIndex) + 3U)) & S_SALT1]);
