            //
            aOrbiterE = (aOrbiterE + aOrbiterA) + 2375439194395137518U;
            aOrbiterG = (aOrbiterG ^ aOrbiterE) ^ 15891659488985436431U;
            aOrbiterG = RotL64((aOrbiterG * 16875105034022167137U), 21U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterF) + 4182104405811929039U;
            aOrbiterA = (aOrbiterA ^ aOrbiterK) ^ 15145791078257534646U;
            aOrbiterA = RotL64((aOrbiterA * 4578170366538405561U), 29U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterJ) + 17969315576150940360U) + aNonceWordO;
            aOrbiterC = (((aOrbiterC ^ aOrbiterF) ^ 13761810831670528253U) ^ aOrbiterUpdateSaltB[(((31U - aIndex) + 19U)) & S_SALT1]) ^ aNonceWordF;
            aOrbiterC = RotL64((aOrbiterC * 1114498193975611699U), 27U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterE) + 4201614632825715572U;
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 2888939072611380044U;
            aOrbiterD = RotL64((aOrbiterD * 1614415786675317133U), 39U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 1906477312079467821U;
