            //
            aOrbiterD = ((aOrbiterD + aOrbiterG) + 11440486078466653962U) + aOrbiterUpdateSaltC[((aIndex + 15U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterD) ^ 8166318673446686392U;
